mapper.update:
UPDATE reader_level
SET points = #{points},
    level = #{level},
    total_borrow_count = #{totalBorrowCount},
    total_return_on_time = #{totalReturnOnTime}
WHERE id = #{id}

UPDATE reader_level
SET points = points + #{points}
WHERE reader_id = #{readerId}

UPDATE reader_level
SET points = GREATEST(points - #{points}, 0)
WHERE reader_id = #{readerId}

UPDATE reader_level
SET total_borrow_count = total_borrow_count + 1
WHERE reader_id = #{readerId}

UPDATE reader_level
SET total_return_on_time = total_return_on_time + 1
WHERE reader_id = #{readerId}
